    private function electrical(): array
    {
        return [
            ['type' => 'section', 'heading' => 'Electrical Service Overview', 'body' => "Electrical work is not a DIY project. Whether you need a panel upgrade to handle modern appliances, new outlets for a home office, or emergency repairs for a tripped breaker, our licensed electricians deliver safe, code-compliant work every time.\n\nWe handle residential and light commercial electrical projects of all sizes. Every job starts with a thorough inspection and a flat-rate quote. We explain what needs to be done, why it matters for your safety, and what it will cost — before we touch a single wire."],
            ['type' => 'section', 'heading' => 'Why Electrical Safety Matters', 'body' => "Your home's electrical system powers everything you rely on, and when it's neglected, the risks add up fast. Staying on top of it protects your home and your family.\n\nPrevent Electrical Fires — Faulty wiring and overloaded circuits are a leading cause of home fires. Regular inspections catch hidden hazards before they become dangerous.\n\nProtect Your Appliances — Proper wiring and surge protection shield your electronics and appliances from damaging power spikes, extending their lifespan.\n\nStay Code-Compliant — Outdated or DIY wiring can fail inspection and void insurance. Licensed work keeps your home up to current electrical code and safe for your family."],
            ['type' => 'image', 'heading' => 'Guardian Air electrician working on a residential electrical panel in New Jersey', 'image_path' => '/img/electrical.webp'],
            ['type' => 'section', 'heading' => 'Signs You Need An Electrician', 'body' => "Electrical problems rarely fix themselves. Watch for these warning signs that it's time to call a licensed pro.\n\nFrequent Tripping — Breakers that trip repeatedly or fuses that blow often signal an overloaded circuit or a wiring fault that needs professional attention.\n\nFlickering or Dimming Lights — Lights that flicker or dim when appliances turn on point to loose connections, an overloaded panel, or aging wiring.\n\nWarm Outlets or Burning Smell — Outlets or switches that feel warm, spark, or give off a burning odor are serious fire hazards. Shut off the circuit and call us right away.\n\nOutdated Panel or Wiring — Homes with a fuse box, aluminum wiring, or a panel under 100 amps often can't safely handle modern electrical demands.\n\nNoticing any of these in your home? Schedule an electrical inspection and we'll get to the root of it."],
            ['type' => 'section', 'heading' => 'Electrical Services We Offer', 'body' => "Here's a quick guide to the electrical work we install, repair, and maintain.\n\nPanel Upgrades — Modernize your electrical panel to safely handle today's appliances, EV chargers, and high-demand circuits with confidence.\n\nWiring & Rewiring — New circuits, full-home rewires, and repairs to damaged or outdated wiring, all done to current code for lasting safety.\n\nLighting & Fixtures — Recessed lighting, ceiling fans, outdoor and accent fixtures installed cleanly to brighten and elevate every room.\n\nOutlets & Switches — New outlets, GFCI installations, dimmers, and smart switches added wherever you need safe, convenient power.\n\nGenerators & EV Chargers — Standby generator hookups and Level 2 EV charger installs that keep you powered and ready for the future."],
            ['type' => 'faq', 'heading' => 'How do I know if my electrical panel needs an upgrade?', 'body' => 'If you have a fuse box, a panel rated under 100 amps, frequently tripping breakers, or you\'re adding major appliances or an EV charger, it\'s likely time for an upgrade. We can assess your panel and recommend the right capacity for your home.'],
            ['type' => 'faq', 'heading' => 'Why do my circuit breakers keep tripping?', 'body' => 'Repeated tripping usually means a circuit is overloaded, or there\'s a short circuit or ground fault. It\'s the breaker doing its job, but persistent tripping points to an underlying issue a licensed electrician should diagnose.'],
            ['type' => 'faq', 'heading' => 'Is it safe to do my own electrical work?', 'body' => 'Swapping a light bulb or resetting a tripped breaker is fine. Anything involving wiring, outlets, panels, or new circuits should be left to a licensed electrician — DIY electrical mistakes can cause fires, shocks, and failed inspections.'],
            ['type' => 'faq', 'heading' => 'What causes flickering or dimming lights?', 'body' => 'Flickering often comes from loose wiring, an overloaded circuit, a failing fixture, or a panel that can\'t keep up with demand. If it happens throughout the house, it\'s worth having the system inspected.'],
            ['type' => 'faq', 'heading' => 'Why do my outlets feel warm or spark?', 'body' => 'A warm outlet, sparking, or a burning smell signals loose connections, overloading, or damaged wiring, all serious fire risks. Stop using the outlet, turn off the circuit, and call us for same-day service.'],
            ['type' => 'faq', 'heading' => 'What is a GFCI outlet and where do I need them?', 'body' => 'A GFCI (Ground Fault Circuit Interrupter) outlet shuts off power instantly if it detects a fault, preventing shocks. Code requires them in kitchens, bathrooms, garages, basements, and outdoor areas.'],
            ['type' => 'faq', 'heading' => 'Can you install an EV charger at my home?', 'body' => 'Yes. We install Level 2 EV chargers, including any panel upgrades or dedicated circuits needed to support them safely. We\'ll evaluate your panel capacity and recommend the best setup for your vehicle.'],
            ['type' => 'faq', 'heading' => 'Do I need a permit for electrical work?', 'body' => 'Most electrical work — panel upgrades, new circuits, and rewiring — requires a permit and inspection. As licensed electricians, we handle the permitting process and ensure every job passes inspection.'],
            ['type' => 'faq', 'heading' => "How often should I have my home's wiring inspected?", 'body' => "We recommend an inspection every few years for newer homes, and sooner for homes over 25 years old or any home you've just purchased. Aluminum wiring and older panels should be checked promptly."],
            ['type' => 'faq', 'heading' => 'What should I do during an electrical emergency?', 'body' => 'If you smell burning, see sparks, or have exposed wiring, shut off power at the breaker if it\'s safe to do so and keep away from the area. Then call us — we offer same-day emergency electrical service.'],
        ];
    }

    private function airQuality(): array
    {
        return [
            ['type' => 'section', 'heading' => 'Air Quality Testing NJ', 'body' => "If your family is dealing with constant dust, allergies, or musty odors, professional air quality testing in NJ is the first step to a healthier home. Guardian Air is a licensed and insured indoor air quality company serving homeowners across Monmouth, Middlesex, and Ocean counties — we test, diagnose, and fix the air you breathe every day.\n\nThe air inside your home can be up to five times more polluted than the air outside. Dust, pollen, pet dander, mold spores, and volatile organic compounds (VOCs) all circulate through your HVAC system and into your lungs. Our technicians assess your home, measure the key factors affecting your air, and recommend the right mix of filtration, humidity control, and purification — with upfront, flat-rate pricing and no pressure.\n\nFrom whole-home air purifiers and UV germicidal lights to mold testing and duct cleaning, we have a solution for every concern and budget."],
            ['type' => 'section', 'heading' => 'Signs of Poor Air Quality', 'body' => "Poor indoor air quality isn't always obvious. Watch for these common warning signs in your New Jersey home.\n\nPersistent Dust — If dust resettles almost as soon as you clean, your air is full of fine particles your filtration is missing.\n\nAllergy & Respiratory Symptoms — Frequent sneezing, congestion, headaches, or irritated eyes indoors often point to high levels of pollen, dander, or other airborne irritants.\n\nMusty or Stale Odors — Lingering smells can signal mold, excess moisture, or stagnant air that needs better ventilation and purification.\n\nHumidity Problems — Condensation on windows, clammy air, or overly dry air that causes static and cracked skin all indicate your home needs humidity control.\n\nNoticing any of these? Schedule an air quality assessment and we'll pinpoint the cause and recommend the right fix."],
            ['type' => 'image', 'heading' => 'Guardian Air technician performing indoor air quality testing in a New Jersey home', 'image_path' => '/img/air-quality-hero.webp'],
            ['type' => 'section', 'heading' => 'Air Quality Solutions for NJ Homes', 'body' => "Based on your testing results, we install and service the full range of indoor air quality solutions.\n\nAir Purifiers — Whole-home systems that capture allergens, dust, smoke, and microscopic particles before they circulate through your living space.\n\nMold Testing & Remediation Guidance — We identify hidden moisture and mold problems and lay out a clear plan to resolve them.\n\nDuct Cleaning — Clears built-up dust, debris, and allergens from your ductwork so the air delivered to every room is as clean as possible.\n\nUV Germicidal Lights — Installed in your HVAC system to neutralize mold, bacteria, and viruses as air passes over the coil.\n\nHumidifiers & Dehumidifiers — Add or remove moisture to keep your home at a healthy, comfortable balance year-round."],
            ['type' => 'section', 'heading' => 'Why NJ Homes Need IAQ', 'body' => "New Jersey's humid summers and tightly sealed, energy-efficient winters create the perfect conditions for poor indoor air quality. Investing in indoor air quality pays off every single day.\n\nProtect Your Health — Cleaner air reduces the allergens, irritants, and airborne contaminants that aggravate asthma and allergies for everyone in your home.\n\nBreathe Easier Every Day — Balanced humidity and proper filtration help your family sleep better, breathe easier, and feel more comfortable year-round.\n\nProtect Your Home & HVAC — Controlling dust, moisture, and contaminants keeps your HVAC system running efficiently and helps prevent mold growth and damage to your home."],
            ['type' => 'section', 'heading' => 'Serving Monmouth, Middlesex & Ocean County', 'body' => "Guardian Air provides indoor air quality testing and solutions to homeowners throughout central New Jersey. Because our technicians are local, we understand the seasonal humidity, pollen, and older-home conditions that affect air quality across the region.\n\nWe proudly serve Toms River, Freehold, Brick, Old Bridge, Red Bank, and Lakewood, along with surrounding communities across all three counties. From the Ocean County shore to the neighborhoods of Middlesex and Monmouth, the same trusted team helps your family breathe cleaner air.\n\nDon't see your town listed? We almost certainly still serve it — give us a call to schedule your air quality assessment today."],
            ['type' => 'faq', 'heading' => 'How much does air quality testing cost in NJ?', 'body' => 'Indoor air quality assessments in New Jersey typically range from a complimentary visual evaluation to a few hundred dollars for detailed testing of particulates, humidity, and contaminants. We explain your options upfront and recommend only what your home actually needs.'],
            ['type' => 'faq', 'heading' => 'What are the most common indoor air pollutants in NJ homes?', 'body' => 'The most common culprits are dust, pollen, pet dander, mold spores, and volatile organic compounds (VOCs) from cleaning products and building materials. New Jersey\'s humid summers also encourage mold and dust mites, while tightly sealed winters trap pollutants indoors.'],
            ['type' => 'faq', 'heading' => 'Does my HVAC filter really affect air quality?', 'body' => 'Yes — significantly. A clogged or low-grade filter lets fine particles recirculate through your home. Most filters should be changed every one to three months, and upgrading to a higher-efficiency (higher-MERV) filter can noticeably improve the air, as long as your system is rated for it.'],
            ['type' => 'faq', 'heading' => 'What is the best air purifier for a whole house?', 'body' => 'For whole-home coverage, a media air purifier or UV-equipped system installed directly into your HVAC ductwork outperforms portable units because it treats all the air your system moves. We size the right solution based on your home and specific air quality concerns.'],
            ['type' => 'faq', 'heading' => 'What is the ideal indoor humidity level?', 'body' => 'Most homes are most comfortable between 30% and 50% relative humidity. Too low causes dry skin and static; too high encourages mold and dust mites. Whole-home humidifiers and dehumidifiers help you maintain the right balance year-round.'],
        ];
    }

    private function drains(): array
    {
        return [
            ['type' => 'section', 'heading' => 'Drain Cleaning Services in NJ', 'body' => "Need fast, reliable drain cleaning in NJ? Guardian Air is a licensed and insured drain and sewer company serving homeowners across Monmouth, Middlesex, and Ocean counties. A slow drain or backed-up sewer line is more than an inconvenience — it can damage your home and create serious health hazards, so we clear it completely instead of just punching a temporary hole through the clog.\n\nWhen needed, we start with a camera inspection so you see exactly what's causing the problem. Then we use the right tool for the job — from motorized snaking to high-pressure hydro jetting that scrubs your pipes clean. Every job comes with upfront, flat-rate pricing, and we leave your home as clean as we found it."],
            ['type' => 'section', 'heading' => 'Signs of a Drain Problem', 'body' => "Catching a drain issue early saves you from a messy, expensive backup. Watch for these warning signs.\n\nSlow Drainage — Water that pools and drains slowly from a sink, tub, or shower is the earliest sign of a developing clog.\n\nGurgling Sounds — Bubbling or gurgling noises mean air is trapped behind a blockage struggling to push through the line.\n\nFoul Odors — Persistent sewage or rotten smells usually point to trapped debris, a venting issue, or a partial blockage deep in the line.\n\nFrequent Clogs — If you're plunging the same drain over and over, the real problem is likely further down the line and needs professional clearing."],
            ['type' => 'image', 'heading' => 'Guardian Air technician performing drain cleaning in a New Jersey home', 'image_path' => '/img/drains-hero.webp'],
            ['type' => 'section', 'heading' => 'Drain Cleaning in Monmouth & Middlesex County', 'body' => "Guardian Air provides trusted drain cleaning throughout Monmouth and Middlesex counties. Homeowners in Freehold, Red Bank, Middletown, Old Bridge, Edison, and Woodbridge rely on us for fast, clean drain and sewer service.\n\nFrom a clogged kitchen sink to a backed-up main line, our local technicians respond quickly with the right equipment to clear it the first time. Because we're nearby, help is never far away when a drain emergency strikes."],
            ['type' => 'section', 'heading' => 'Sewer Repair & Line Replacement', 'body' => "A failing sewer line causes repeat backups, foul odors, and serious health hazards. From spot repairs to full line replacement, we fix cracked, collapsed, and root-invaded sewer lines and restore reliable flow.\n\nTree roots are a common culprit in older New Jersey neighborhoods — they grow into tiny cracks or joints and cause major blockages over time. A camera inspection confirms the issue so we recommend the right repair, not a guess."],
            ['type' => 'section', 'heading' => 'Hydro Jetting', 'body' => "Hydro jetting uses high-pressure water to scour the inside of your pipes clean — blasting away grease, scale, and roots that snaking leaves behind. It's the most thorough fix for stubborn and recurring clogs, and it's completely safe for healthy pipes.\n\nIf you find yourself clearing the same drain again and again, hydro jetting restores the line to like-new flow and buys you years before the next problem."],
            ['type' => 'section', 'heading' => 'Camera Inspection', 'body' => "A waterproof camera travels through your line so you can see the exact cause and location of a problem — no demolition guesswork. We use camera inspections to diagnose chronic clogs, locate breaks and root intrusion, and verify the line is fully clear after the job.\n\nIt's the smartest way to confirm what's really happening inside your pipes before spending money on a repair."],
            ['type' => 'section', 'heading' => 'Emergency Drain Service', 'body' => "When a main line backs up or a drain floods, it can't wait. Guardian Air offers same-day and 24/7 emergency drain service across Monmouth, Middlesex, and Ocean counties — including Toms River, Brick, Lakewood, Freehold, and the surrounding towns.\n\nCall and you'll reach a real person who dispatches a technician fast to clear the blockage and protect your home from water damage — at the same flat rate, day or night."],
            ['type' => 'faq', 'heading' => 'How much does drain cleaning cost in NJ?', 'body' => 'Most drain cleaning in New Jersey ranges from about $150 to $500 depending on the location and severity of the clog, with hydro jetting on the higher end. We provide a flat-rate quote upfront with no hidden fees, so you know the cost before we start.'],
            ['type' => 'faq', 'heading' => 'What are the signs I need a sewer line replacement?', 'body' => 'Frequent main-line backups, multiple drains clogging at once, sewage odors, soggy patches in the yard, and recurring root intrusion all point to a failing sewer line. A camera inspection confirms whether a spot repair will do or full replacement is needed.'],
            ['type' => 'faq', 'heading' => 'Why do my drains keep clogging?', 'body' => 'Chronic clogs are usually caused by grease buildup, hair, soap scum, mineral scale, or tree roots in the main line. A one-time clearing may not solve a deeper issue, so we inspect the line to find and fix the real cause — often with hydro jetting.'],
            ['type' => 'faq', 'heading' => 'Do you offer emergency drain service in Monmouth County?', 'body' => 'Yes. We provide same-day and 24/7 emergency drain and sewer service across Monmouth County, including Freehold, Red Bank, Middletown, and Howell. Call any time and we\'ll dispatch a technician quickly at our standard flat rate.'],
            ['type' => 'faq', 'heading' => 'Is hydro jetting better than snaking?', 'body' => 'Snaking is great for breaking through a single clog quickly, while hydro jetting cleans the entire interior of the pipe, removing grease, scale, and roots. For recurring or severe clogs, hydro jetting delivers a more thorough, longer-lasting result.'],
        ];
    }

